sql:
SELECT COUNT(text_id) AS total_texts_published_2022
FROM texts
WHERE publication_date LIKE '2022%';

SELECT text_id
FROM texts
WHERE text_quality_score > 0.9;

SELECT text_category, COUNT(*) AS text_count
FROM texts
GROUP BY text_category;

SELECT text_id, author, text_category
FROM texts
ORDER BY publication_date DESC;

SELECT COUNT(DISTINCT relationship_id) AS distinct_relationship_count
FROM relationships
WHERE relation_type = 'is prescribed for';

SELECT relation_type
FROM relationships
WHERE relationship_frequency = (SELECT MAX(relationship_frequency) FROM relationships);

external_knowledge:
- 'Strongest alliances' refers to relationships with a relevance score greater than 0.7;
- 'Depth of their connection' corresponds to the relevance score in the database;
- 'Frequency of interaction' is indicated by the relationship frequency;
- The query focuses on pairs of entities (entity1 and entity2) and their interactions, sorted by relevance and frequency in descending order.

sql:
SELECT AVG(t.text_sentiment) AS average_sentiment
FROM texts t
WHERE t.text_category = 'medication';
